def keep_features_dicts_synced(func):
    """
    Wrapper to keep the secondary dictionary, `_column_requires_decoding`, of the `Features` object
    in sync with the main dictionary `self`, whenever `func` (i.e. some dictionary method) is called.
    This is used to keep the private dictionary in sync with the public dictionary state whenever a
    method that mutates the dictionary (`__setitem__`, `__delitem__`, `update`, `pop`, etc.) is called,
    instead of having to override and duplicate the logic of every single one of those methods.
    """

    @wraps(func)
    def wrapper(*args, **kwargs):
        if args:
            self: "Features" = args[0]
            args = args[1:]
        else:
            self: "Features" = kwargs.pop("self")
        out = func(self, *args, **kwargs)
        assert hasattr(self, "_column_requires_decoding")
        self._column_requires_decoding = {col: require_decoding(feature) for col, feature in self.items()}
        return out

    wrapper._decorator_name_ = "_keep_dicts_synced"
    return wrapper


